import{toProductionEntry}from"../../util/input.js";import{hasDependency}from"../../util/plugin.js";import{config}from"../astro/index.js";import{getComponentPathsFromSourceFile}from"./resolveFromAST.js";const title="Starlight",enablers=["@astrojs/starlight"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),resolveFromAST=e=>{const o=getComponentPathsFromSourceFile(e);return Array.from(o).map(e=>toProductionEntry(e))},plugin={title:title,enablers:enablers,isEnabled:isEnabled,config:config,resolveFromAST:resolveFromAST};export default plugin;